function roundRect(ctx,x,y,w,h,radius){var r=x+w;var b=y+h;ctx.beginPath();ctx.moveTo(x+radius,y);ctx.lineTo(r-radius,y);ctx.quadraticCurveTo(r,y,r,y+radius);ctx.lineTo(r,y+h-radius);ctx.quadraticCurveTo(r,b,r-radius,b);ctx.lineTo(x+radius,b);ctx.quadraticCurveTo(x,b,x,b-radius);ctx.lineTo(x,y+radius);ctx.quadraticCurveTo(x,y,x+radius,y);ctx.fill();ctx.stroke();}
class CanvasButtons{constructor(canvas){this.canvas=canvas;this.ctx=document.getElementById(this.canvas).getContext('2d');this.buttonlist=new Array();this.clearButtons=this.clearButtons.bind(this);this.addButton=this.addButton.bind(this);this.checkButtonClick=this.checkButtonClick.bind(this);$('#'+this.canvas).on('click',this.checkButtonClick);}
clearButtons(){this.buttonlist.length=0;}
addButton(x,y,width,height,buttontext,textcolor,buttoncolor,callback,callbackData,roundCorner){if(typeof(roundCorner)==='undefined'){roundCorner=0;}
this.ctx.strokeStyle='#000000';this.ctx.fillStyle=buttoncolor;if(!roundCorner){this.ctx.fillRect(x,y,width,height);this.ctx.strokeRect(x,y,width,height);}else{roundRect(this.ctx,x,y,width,height,roundCorner);}
this.ctx.fillStyle=textcolor;this.ctx.strokeStyle=textcolor;if(!buttontext.includes("\n")){this.ctx.fillText(buttontext,x+8,y+(height/2));}else{var blines=buttontext.split("\n");var yoffs=y+((height/2)-(9*(blines.length-1)));var i;for(i=0;i<blines.length;i++){blines[i].replace("\n",'');this.ctx.fillText(blines[i],x+8,yoffs);yoffs=yoffs+18;}}
var thisbutton={startx:x,starty:y,endx:x+width,endy:y+height,displaytext:buttontext,callback:callback,callbackData:callbackData};this.buttonlist.push(thisbutton);return;}
checkButtonClick(e){var canvas=$('#'+this.canvas);var x=Math.floor((e.pageX-canvas.offset().left));var y=Math.floor((e.pageY-canvas.offset().top));for(var i=0;i<this.buttonlist.length;i++){if(x>=this.buttonlist[i].startx&&x<=this.buttonlist[i].endx&&y>=this.buttonlist[i].starty&&y<=this.buttonlist[i].endy){this.buttonlist[i].callback(this.buttonlist[i].callbackData);}}
return;}}
class Canvas7Segment{constructor(canvas){this.canvas=canvas;this.ctx=document.getElementById(this.canvas).getContext('2d');this.buttonlist=[];$('#'+this.canvas).on('click',this.checkButtonClick);this.segmentcoords=[[24,25,31,16,118,16,126,25,118,34,32,34],[21,28,30,36,30,94,21,103,12,95,12,37],[128,28,137,36,137,94,128,103,121,95,121,37],[21,110,29,117,29,175,21,184,13,175,12,118],[129,109,137,117,137,176,129,184,120,176,120,118],[24,187,33,178,117,178,125,187,118,196,32,196],[24,106,32,97,118,97,125,105,118,114,32,114],[125,200,141,186,151,210],[64,55,78,55,78,68,64,68,-1,-1,64,148,78,148,78,161,64,161]];}
sevensegmentDrawSegment(startx,starty,segment,scale){var coords=this.segmentcoords[segment-1];var isfirst=1;this.ctx.beginPath();for(var i=0;i<coords.length;i=i+2){var x=coords[i];var y=coords[i+1];if(x==-1&&y==-1){this.ctx.closePath();this.ctx.fill();this.ctx.stroke();this.ctx.beginPath();isfirst=1;continue;}
x=(x-20)*scale/16;y=(y-15)*scale/16;x=x+startx;y=y+starty;if(isfirst){this.ctx.moveTo(x,y);isfirst=0;}else{this.ctx.lineTo(x,y);}}
this.ctx.closePath();this.ctx.fill();this.ctx.stroke();return;}
sevensegmentDrawDigit(x,y,digit,scale){var segments='';if(digit===' '){segments="";}else if(digit==='0'){segments="123456";}else if(digit==='1'){segments="35";}else if(digit==='2'){segments="13746";}else if(digit==='3'){segments="13756";}else if(digit==='4'){segments="2735";}else if(digit==='5'){segments="12756";}else if(digit==='6'){segments="127456";}else if(digit==='7'){segments="135";}else if(digit==='8'){segments="1234567";}else if(digit==='9'){segments="123567";}else if(digit==='0'){segments="123456";}else if(digit==='.'){segments='8';}else if(digit===':'){segments="9";}else if(digit==='-'){segments="7";}
var parts=segments.split('');var i;for(i=0;i<parts.length;i++){this.sevensegmentDrawSegment(x,y,parts[i],scale);}
return;}
sevensegmentDrawText(x,y,seventext,scale){var parts=seventext.split('');var i;for(i=0;i<parts.length;i++){this.sevensegmentDrawDigit(x+(i*11*scale),y,parts[i],scale);}
return;}}
class CanvasItemlist{constructor(canvas,scrollCallback,selectCallback){this.canvas=canvas;this.scrollCallback=scrollCallback;this.selectCallback=selectCallback;this.ctx=document.getElementById(this.canvas).getContext('2d');this.buttonlist=[];this.checkButtonClick=this.checkButtonClick.bind(this);this.canvasMouseDown=this.canvasMouseDown.bind(this);this.canvasMouseUp=this.canvasMouseUp.bind(this);this.canvasMouseMove=this.canvasMouseMove.bind(this);$('#'+this.canvas).on('click',this.checkButtonClick);$(document).on('mousedown',this.canvasMouseDown);$(document).on('mousemove',this.canvasMouseMove);$(document).on('mouseup',this.canvasMouseUp);this.mousedown=0;this.mousey=0;this.itemlistcount=0;this.itemoffset=0;this.itemsizepixels=0;}
canvasMouseDown(e){if(this.buttonlist.length==0){return;}
var canvas=$('#'+this.canvas);var x=Math.floor((e.pageX-canvas.offset().left));var y=Math.floor((e.pageY-canvas.offset().top));for(var i=0;i<this.buttonlist.length;i++){if(x>=this.buttonlist[i].startx&&x<=this.buttonlist[i].endx&&y>=this.buttonlist[i].starty&&y<=this.buttonlist[i].endy&&this.buttonlist[i].scrollListEvent==='drag'){this.mousedown=1;}}
return;}
canvasMouseUp(e){this.mousedown=0;return;}
canvasMouseMove(e){if(!this.mousedown){return;}
var newmousey=e.pageY-$("#poscanvas").offset().top;var diff=this.mousey-newmousey;if(diff>this.itemsizepixels&&this.itemoffset>0){this.mousey=this.mousey-this.itemsizepixels;this.itemoffset=this.itemoffset-1;this.scrollCallback(this.itemoffset);}else if(diff<(-1*this.itemsizepixels)){this.mousey=this.mousey+this.itemsizepixels;this.itemoffset=this.itemoffset+1;this.scrollCallback(this.itemoffset);}
return;}
clearButtons(){this.buttonlist.length=0;}
addScrollList(x,y,width,height,itemList,scrollOffset,selectedItem){this.ctx.fillStyle='#FFFFFF';this.ctx.strokeStyle='#000000';this.ctx.fillRect(x,y,width-1,height-1);this.ctx.strokeRect(x,y,width-1,height-1);var listCount=Math.floor((height-10)/24);if(scrollOffset==-1||scrollOffset>(itemList.length-listCount)){scrollOffset=itemList.length-listCount;if(scrollOffset<0){scrollOffset=0;}
this.scrollCallback(scrollOffset);}
if(selectedItem!=-1){var selector=selectedItem-scrollOffset;if(selector=>0&&selector<listCount){this.ctx.fillStyle='#F8FC03';this.ctx.fillRect(x+1,y+1+(selector*24),width-25,24);}}
this.ctx.font="20px Courier";this.ctx.fillStyle='#000000';var maxItemCount=listCount;if(itemList.length<maxItemCount){maxItemCount=itemList.length;}
for(var i=0;i<maxItemCount;i++){if(itemList[i+scrollOffset].match(/^\^#/)){var textcolor=itemList[i+scrollOffset].substr(1,7);this.ctx.fillStyle='#00FF00';var tempitem=itemList[i+scrollOffset].substring(8);this.ctx.fillText(tempitem,x+5,y+20+(i*24));}else{this.ctx.fillStyle='#000000';this.ctx.fillText(itemList[i+scrollOffset],x+5,y+20+(i*24));}
this.buttonlist.push({startx:x+1,starty:y+1+(i*24),endx:x+1+width-24,endy:y+1+(i*24)+23,selectItem:i+scrollOffset,scrollListEvent:'select'});}
this.ctx.strokeStyle='#000000';this.ctx.fillStyle='#000000';this.ctx.font="20px Courier";this.ctx.strokeRect(x+width-23,y+3,20,20);this.ctx.fillText('⮝',x+width-22,y+22);if(scrollOffset>0){this.buttonlist.push({startx:x+width-23,starty:y+3,endx:x+width-23+20,endy:y+3+20,scrollListEvent:'scroll',scrollTo:scrollOffset-1});}
this.ctx.strokeRect(x+width-23,y+height-23,20,20);this.ctx.fillText('⮟',x+width-22,y+height-8);if(scrollOffset<(itemList.length-listCount)){this.buttonlist.push({startx:x+width-23,starty:y+height-23,endx:x+width-23+20,endy:y+height-23+20,scrollListEvent:'scroll',scrollTo:scrollOffset+1});}
var totallen=(y+height-23)-(y+23)-4;var barlen=totallen;var barstart=y+25;if(itemList.length>listCount){var lenpercent=listCount/itemList.length;barlen=Math.floor(barlen*lenpercent);var startpercent=invoicelistoffset/invoicelist.length;barstart=barstart+Math.floor(totallen*startpercent);}
this.ctx.fillStyle='#000000';this.ctx.fillRect(x+width-23,barstart,20,barlen);if(barstart>y+25){var scrolltmp=scrollOffset-10;if(scrolltmp<0){scrolltmp=0;}
this.buttonlist.push({startx:x+width-23,starty:y+25,endx:x+width-23+20,endy:barstart,scrollListEvent:'scroll',scrollTo:scrolltmp});}
this.itemoffset=scrollOffset;this.itemsizepixels=(barlen/totallen)*listCount;if((barstart+barlen)<(y+25+totallen)){var scrolltmp=scrollOffset+10;if(scrolltmp>(itemList.length-listCount)){scrolltmp=itemList.length-listCount;}
this.buttonlist.push({startx:x+width-23,starty:barstart+barlen,endx:x+width-23+20,endy:y+25+totallen,scrollListEvent:'scroll',scrollTo:scrolltmp});}
this.buttonlist.push({startx:x+width-23,starty:barstart,endx:x+width-23+20,endy:barstart+barlen,scrollListEvent:'drag',});return listCount;}
checkButtonClick(e){if(this.buttonlist.length==0){return;}
var canvas=$('#'+this.canvas);var x=Math.floor((e.pageX-canvas.offset().left));var y=Math.floor((e.pageY-canvas.offset().top));for(var i=0;i<this.buttonlist.length;i++){if(x>=this.buttonlist[i].startx&&x<=this.buttonlist[i].endx&&y>=this.buttonlist[i].starty&&y<=this.buttonlist[i].endy){if(this.buttonlist[i].scrollListEvent==='select'){this.selectCallback(this.buttonlist[i].selectItem);}else if(this.buttonlist[i].scrollListEvent==='scroll'){this.scrollCallback(this.buttonlist[i].scrollTo);}}}
return;}}
